from typing import Dict, Any, Tuple
import threading
import time

class SessionManager:
    def __init__(self):
        self.sessions: Dict[str, Tuple[int, threading.Thread]] = {}
        self.lock = threading.Lock()

    def create_session(self, timeout: int) -> str:
        with self.lock:
            session_id = self._generate_session_id()
            self.sessions[session_id] = (timeout, threading.Thread(target=self._run_session, args=(session_id, timeout)))
            self.sessions[session_id][1].start()
            return session_id

    def close_session(self, session_id: str) -> None:
        with self.lock:
            if session_id not in self.sessions:
                raise ValueError(f"Session {session_id} does not exist.")
            _, thread = self.sessions[session_id]
            thread.join()
            del self.sessions[session_id]

    def modify_session(self, session_id: str, new_timeout: int) -> None:
        with self.lock:
            if session_id not in self.sessions:
                raise ValueError(f"Session {session_id} does not exist.")
            _, thread = self.sessions[session_id]
            thread.join()
            self.sessions[session_id] = (new_timeout, threading.Thread(target=self._run_session, args=(session_id, new_timeout)))
            self.sessions[session_id][1].start()

    def get_session_status(self, session_id: str) -> str:
        with self.lock:
            if session_id not in self.sessions:
                raise ValueError(f"Session {session_id} does not exist.")
            _, thread = self.sessions[session_id]
            thread.join()
            if thread.is_alive():
                return "active"
            else:
                return "closed"

    def _generate_session_id(self) -> str:
        # For simplicity, we'll use the current time in milliseconds as the session ID
        import time
        return str(int(time.time() * 1000))

    def _run_session(self, session_id: str, timeout: int) -> None:
        while True:
            time.sleep(timeout / 1000)
            # For simplicity, we'll assume the session is active if it's still running
            pass

def main():
    manager = SessionManager()
    session_id = manager.create_session(10)  # Create a new session with a 10-second timeout
    print(manager.get_session_status(session_id))  # Should print "active"
    manager.modify_session(session_id, 20)  # Update the session timeout to 20 seconds
    print(manager.get_session_status(session_id))  # Should print "active"
    manager.close_session(session_id)  # Close the session
    print(manager.get_session_status(session_id))  # Should print "closed"

if __name__ == "__main__":
    main()
