    public static final String COMMAND_CHECK_STATUS = "checkStatus";

    // Data structure to store room configurations
    private static class RoomConfig {
        boolean isOn;
        int brightness;

        public RoomConfig(boolean isOn, int brightness) {
            this.isOn = isOn;
            this.brightness = brightness;
        }
    }

    // Data structure to store command history
    private static class CommandHistory {
        String[] history;

        public CommandHistory(int maxHistory) {
            this.history = new String[maxHistory];
            this.historyIndex = 0;
        }

        public void recordCommand(String command) {
            if (historyIndex < history.length) {
                history[historyIndex++] = command;
            } else {
                // Handle command history overflow
                System.out.println("Command history overflow. Old commands will be discarded.");
                for (int i = 0; i < historyIndex; i++) {
                    history[i] = history[i + 1];
                }
                history[historyIndex] = command;
                historyIndex++;
            }
        }

        public String getCommandHistory() {
            String result = "";
            for (String command : history) {
                result += command + "\n";
            }
            return result;
        }
    }

    // Data structure to store room configurations
    private static RoomConfig[] roomConfigs = new RoomConfig[4];
    private static CommandHistory commandHistory = new CommandHistory(10);

