                    break;
                case 2:
                    System.out.print("Enter room name (Kitchen, Living Room, Bedroom, Bathroom): ");
                    room = System.console().readLine();
                    if (room.equals(KITCHEN) || room.equals(LIVING_ROOM) || room.equals(BEDROOM) || room.equals(BATHROOM)) {
