                    if (room.equals(KITCHEN) || room.equals(LIVING_ROOM) || room.equals(BEDROOM) || room.equals(BATHROOM)) {
                        System.out.print("Enter brightness level (0-" + MAX_BRIGHTNESS + "): ");
                        int brightness = Integer.parseInt(System.console().readLine());
                        if (brightness >= MIN_BRIGHTNESS && brightness <= MAX_BRIGHTNESS) {
