                        }
                    } else {
                        System.out.println("Invalid room name. Please try again.");
                    }
                    break;
                case 4:
                    System.out.print("Enter room name (Kitchen, Living Room, Bedroom, Bathroom): ");
                    room = System.console().readLine();
                    if (room.equals(KITCHEN) || room.equals(LIVING_ROOM) || room.equals(BEDROOM) || room.equals(BATHROOM)) {
                        checkStatus(room);
                    } else {
                        System.out.println("Invalid room name. Please try again.");
                    }
                    break;
                case 5:
                    System.out.println(commandHistory.getCommandHistory());
                    break;
                case 6:
                    System.exit(0);
                default:
                    System.out.println("Invalid option. Please try again.");
            }
        }
    }

    public static void turnOn(String room) {
        for (int i = 0; i < roomConfigs.length; i++) {
            if (roomConfigs[i].roomName.equals(room)) {
                roomConfigs[i].isOn = true;
                commandHistory.recordCommand(COMMAND_TURN_ON + " " + room);
                System.out.println("Lights turned on in " + room);
                return;
            }
        }
        System.out.println("Invalid room name. Please try again.");
