        for (int i = 0; i < roomConfigs.length; i++) {
            if (roomConfigs[i].roomName.equals(room)) {
                roomConfigs[i].isOn = false;
                commandHistory.recordCommand(COMMAND_TURN_OFF + " " + room);
                System.out.println("Lights turned off in " + room);
                return;
            }
        }
        System.out.println("Invalid room name. Please try again.");
    }

    public static void adjustBrightness(String room, int brightness) {
        for (int i = 0; i < roomConfigs.length; i++) {
            if (roomConfigs[i].roomName.equals(room)) {
                roomConfigs[i].brightness = brightness;
                commandHistory.recordCommand(COMMAND_ADJUST_BRIGHTNESS + " " + room + " " + brightness);
