class HardwareStore {
public:
    void add(const std::string& item_name, int quantity, double price);
    void remove(const std::string& item_name);
    void update(const std::string& item_name, int new_quantity, double new_price);
    void display() const;

protected:
    int calculateTotalCost(const std::string& item_name) const;

private:
    std::map<std::string, InventoryItem> inventory;
    int numItems = 0;
};

class InventoryItem {
public:
    InventoryItem(const std::string& item_name, int quantity, double price) 
        : item_name(item_name), quantity(quantity), price(price) {}

    std::string getItemName() const { return item_name; }
    int getQuantity() const { return quantity; }
    double getPrice() const { return price; }

private:
    std::string item_name;
    int quantity;
    double price;
};

void HardwareStore::add(const std::string& item_name, int quantity, double price) {
    if (inventory.find(item_name) != inventory.end()) {
        std::cout << "Item already exists in the inventory." << std::endl;
        return;
    }

    inventory[item_name] = InventoryItem(item_name, quantity, price);
    numItems++;
}

void HardwareStore::remove(const std::string& item_name) {
    if (inventory.find(item_name) == inventory.end()) {
        std::cout << "Item does not exist in the inventory." << std::endl;
        return;
    }

    inventory.erase(item_name);
    numItems--;
}

void HardwareStore::update(const std::string& item_name, int new_quantity, double new_price) {
    if (inventory.find(item_name) == inventory.end()) {
        std::cout << "Item does not exist in the inventory." << std::endl;
        return;
    }

    inventory[item_name].quantity = new_quantity;
    inventory[item_name].price = new_price;
}

void HardwareStore::display() const {
    std::cout << "Hardware Store Inventory:" << std::endl;
    for (const auto& item : inventory) {
        std::cout << "Name: " << item.second.getItemName() << ", Quantity: " << item.second.getQuantity()
                  << ", Price: $" << item.second.getPrice() << std::endl;
    }
}

int HardwareStore::calculateTotalCost(const std::string& item_name) const {
    if (inventory.find(item_name) == inventory.end()) {
        std::cout << "Item does not exist in the inventory." << std::endl;
        return 0;
    }

    return inventory[item_name].quantity * inventory[item_name].price;
}

int main() {
