function processChartData(data) {
    const bucketHours = ['00:00-01:00', '01:00-02:00', '02:00-03:00', '03:00-04:00', '04:00-05:00', 
                        '05:00-06:00', '06:00-07:00', '07:00-08:00', '08:00-09:00', '09:00-10:00', 
                        '10:00-11:00', '11:00-12:00', '12:00-13:00', '13:00-14:00', '14:00-15:00', 
                        '15:00-16:00', '16:00-17:00', '17:00-18:00', '18:00-19:00', '19:00-20:00', 
                        '20:00-21:00', '21:00-22:00', '22:00-23:00', '23:00-00:00'];
    const result = {};

    for (const dataPoint of data) {
        const hour = getHourFromTimestamp(dataPoint.timestamp);
        if (!result[bucketHours[hour]]) {
            result[bucketHours[hour]] = [];
        }
        result[bucketHours[hour]].push(dataPoint.value);
    }

    for (const bucket in result) {
        const averageValue = result[bucket].reduce((sum, value) => sum + value, 0) / result[bucket].length;
        result[bucket] = averageValue;
    }

    return result;
}

function getHourFromTimestamp(timestamp) {
    const date = new Date(timestamp);
    const hours = date.getHours();
    const hourString = hours.toString().padStart(2, '0');
    const minuteString = date.getMinutes().toString().padStart(2, '0');
    return hourString + ':' + minuteString;
}
