use std::collections::HashMap;
use std::error::Error;
use std::result::Result;

struct AuthenticationSystem {
    users: HashMap<String, (String, String)>,
}

impl AuthenticationSystem {
    fn new() -> Self {
        AuthenticationSystem {
            users: HashMap::new(),
        }
    }

    fn register_user(&mut self, username: String, password: String) -> Result<(), Box<dyn Error>> {
        if self.users.contains_key(&username) {
            return Err("Username already exists".into());
        }
        self.users.insert(username, (password, "".to_string()));
        Ok(())
    }

    fn login_user(&self, username: String, password: String) -> Result<String, Box<dyn Error>> {
        if !self.users.contains_key(&username) {
            return Err("Username not found".into());
        }
        let (stored_password, _) = self.users.get(&username)?;
        if stored_password != &password {
            return Err("Incorrect password".into());
        }
        Ok("Success".to_string())
    }

    fn update_password(&mut self, username: String, old_password: String, new_password: String) -> Result<String, Box<dyn Error>> {
        if !self.users.contains_key(&username) {
            return Err("Username not found".into());
        }
        let (stored_password, _) = self.users.get(&username)?;
        if stored_password == &old_password {
            self.users.insert(username, (new_password, ""));
            Ok("Updated".to_string())
        } else {
            Err("Invalid old password".into())
        }
    }

    fn delete_user(&mut self, username: String) -> Result<String, Box<dyn Error>> {
        if !self.users.contains_key(&username) {
            return Err("User not found".into());
        }
        self.users.remove(&username);
        Ok("Deleted".to_string())
    }
}

fn main() {
    let mut auth_system = AuthenticationSystem::new();

    // Register users
    auth_system.register_user("user1".to_string(), "password1".to_string()).unwrap();
    auth_system.register_user("user2".to_string(), "password2".to_string()).unwrap();

    // Login users
    println!("{}", auth_system.login_user("user1".to_string(), "password1".to_string()).unwrap());
    println!("{}", auth_system.login_user("user1".to_string(), "wrong_password".to_string()).unwrap_err());

    // Update passwords
    auth_system.update_password("user1".to_string(), "password1".to_string(), "new_password1".to_string()).unwrap();
    println!("{}", auth_system.update_password("user1".to_string(), "wrong_password".to_string(), "new_password1".to_string()).unwrap_err());

    // Delete users
    auth_system.delete_user("user1".to_string()).unwrap();
    println!("{}", auth_system.delete_user("user1".to_string()).unwrap_err());
}
