from datetime import datetime

# Dictionary to store project times
project_times = {}

def add_project(project_name):
    """Registers a new project with the specified name."""
    global project_times
    if project_name not in project_times:
        project_times[project_name] = {"start_time": None, "stop_time": None}
    else:
        print(f"Project '{project_name}' already exists.")

def start_time(project_name, time):
    """Records the start time for a designated project."""
    global project_times
    if project_name not in project_times:
        print(f"Project '{project_name}' does not exist. Use ADD_PROJECT to create it.")
        return
    if project_times[project_name]["start_time"] is not None:
        print(f"Project '{project_name}' is already started. Use STOP_TIME to stop it.")
        return
    try:
        start_time_obj = datetime.strptime(time, "%H:%M")
        project_times[project_name]["start_time"] = start_time_obj
    except ValueError:
        print("Invalid time format. Use HH:MM.")

def stop_time(project_name, time):
    """Notes the stop time for a project."""
    global project_times
    if project_name not in project_times:
        print(f"Project '{project_name}' does not exist. Use ADD_PROJECT to create it.")
        return
    if project_times[project_name]["start_time"] is None:
        print(f"Project '{project_name}' is not started. Use START_TIME to start it.")
        return
    try:
        stop_time_obj = datetime.strptime(time, "%H:%M")
        project_times[project_name]["stop_time"] = stop_time_obj
    except ValueError:
        print("Invalid time format. Use HH:MM.")

def report(project_name):
    """Generates and prints the total number of hours and minutes spent on a project."""
    global project_times
    if project_name not in project_times:
        print(f"Project '{project_name}' does not exist.")
        return
    if project_times[project_name]["start_time"] is None or project_times[project_name]["stop_time"] is None:
        print(f"Project '{project_name}' is not started or stopped.")
        return
    total_time = project_times[project_name]["stop_time"] - project_times[project_name]["start_time"]
    hours = total_time.seconds // 3600
    minutes = (total_time.seconds // 60) % 60
    print(f"Total time spent on '{project_name}': {hours} hours {minutes} minutes")

def main():
    while True:
        command = input("Enter a command (ADD_PROJECT, START_TIME, STOP_TIME, REPORT, EXIT): ")
        if command == "EXIT":
            break
        elif command.startswith("ADD_PROJECT "):
            project_name = command[11:]
            add_project(project_name)
        elif command.startswith("START_TIME "):
            project_name, time = command[9:].split()
            start_time(project_name, time)
        elif command.startswith("STOP_TIME "):
            project_name, time = command[9:].split()
            stop_time(project_name, time)
        elif command == "REPORT":
            project_name = input("Enter project name: ")
            report(project_name)
        else:
            print("Invalid command.")

if __name__ == "__main__":
    main()
