class TemperatureManager {
  constructor() {
    this.records = {};
  }

  addRecord(location, temperature) {
    if (!this.records[location]) {
      this.records[location] = {};
    }
    this.records[location][temperature] = (this.records[location][temperature] || 0) + 1;
  }

  getAverage(location) {
    if (!this.records[location]) {
      throw new Error(`No temperature records available for location '${location}'`);
    }
    const totalEntries = Object.values(this.records[location]).reduce((a, b) => a + b, 0);
    if (totalEntries === 0) {
      throw new Error(`No temperature records available for location '${location}'`);
    }
    const average = Object.values(this.records[location]).reduce((a, b) => a + b, 0) / totalEntries;
    return average;
  }

  removeRecord(location, date) {
    if (!this.records[location]) {
      throw new Error(`No temperature records available for location '${location}'`);
    }
    if (!this.records[location][date]) {
      throw new Error(`No temperature record found for location '${location}' on date '${date}'`);
    }
    delete this.records[location][date];
    if (Object.keys(this.records[location]).length === 0) {
      delete this.records[location];
    }
  }

  updateRecord(location, date, newTemperature) {
    if (!this.records[location]) {
      throw new Error(`No temperature records available for location '${location}'`);
    }
    if (!this.records[location][date]) {
      throw new Error(`No temperature record found for location '${location}' on date '${date}'`);
    }
    this.records[location][date] = newTemperature;
  }
}

function manageTemperatureRecords() {
  const temperatureManager = new TemperatureManager();
  return temperatureManager;
}

const manager = manageTemperatureRecords();
