use std::fs;
use std::path::Path;

pub struct FileManager {
    root_dir: String,
}

impl FileManager {
    pub fn new() -> FileManager {
        FileManager {
            root_dir: String::from("files"),
        }
    }

    pub fn create_file(&mut self, path: &str, content: &str) -> Result<(), std::io::Error> {
        let mut file_path = Path::new(&self.root_dir);
        file_path.push(path);
        fs::write(file_path, content)
    }

    pub fn read_file(&mut self, path: &str) -> Result<String, std::io::Error> {
        let mut file_path = Path::new(&self.root_dir);
        file_path.push(path);
        fs::read_to_string(file_path)
    }

    pub fn update_file(&mut self, path: &str, new_content: &str) -> Result<(), std::io::Error> {
        let mut file_path = Path::new(&self.root_dir);
        file_path.push(path);
        fs::write(file_path, new_content)
    }

    pub fn delete_file(&mut self, path: &str) -> Result<(), std::io::Error> {
        let mut file_path = Path::new(&self.root_dir);
        file_path.push(path);
        fs::remove_file(file_path)
    }
}
