#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the structure for a process record
typedef struct Process {
    char name[100];
    int priority;
    struct Process* next;
} Process;

// Function to create a new process record
Process* createProcess(char* name, int priority) {
    Process* process = (Process*)malloc(sizeof(Process));
    strcpy(process->name, name);
    process->priority = priority;
    process->next = NULL;
    return process;
}

// Function to add a process to the task manager
void addProcess(Process** taskManager, char* name, int priority) {
    Process* newProcess = createProcess(name, priority);
    if (*taskManager == NULL || (*taskManager)->priority > priority) {
        newProcess->next = *taskManager;
        *taskManager = newProcess;
    } else {
        Process* current = *taskManager;
        while (current->next != NULL && current->next->priority > priority) {
            current = current->next;
        }
        newProcess->next = current->next;
        current->next = newProcess;
    }
}

// Function to kill a process by name
void killProcess(Process** taskManager, char* name) {
    if (*taskManager == NULL) {
        return;
    }
    if (strcmp((*taskManager)->name, name) == 0) {
        Process* temp = *taskManager;
        *taskManager = *taskManager->next;
        free(temp);
        return;
    }
    Process* current = *taskManager;
    while (current->next != NULL) {
        if (strcmp(current->next->name, name) == 0) {
            Process* temp = current->next;
            current->next = current->next->next;
            free(temp);
            return;
        }
        current = current->next;
    }
}

// Function to kill all processes with a given priority
void killPriorityProcess(Process** taskManager, int priority) {
    if (*taskManager == NULL) {
        return;
    }
    if ((*taskManager)->priority == priority) {
        Process* temp = *taskManager;
        *taskManager = *taskManager->next;
        free(temp);
        return;
    }
    Process* current = *taskManager;
    while (current->next != NULL) {
        if (current->next->priority == priority) {
            Process* temp = current->next;
            current->next = current->next->next;
            free(temp);
            return;
        }
        current = current->next;
    }
}

// Function to display all current processes sorted by priority
void listProcesses(Process* taskManager) {
    if (taskManager == NULL) {
        printf("No processes available.\n");
        return;
    }
    Process* current = taskManager;
    while (current != NULL) {
        printf("Name: %s, Priority: %d\n", current->name, current->priority);
        current = current->next;
    }
}

// Function to manage the task manager
void taskManagerMain() {
    Process* taskManager = NULL;
    char name[100];
    int priority;
    char choice;
    while (1) {
        printf("Task Manager Menu:\n");
        printf("1. ADD name priority\n");
        printf("2. KILL name\n");
        printf("3. KILL_PRIORITY priority\n");
        printf("4. LIST\n");
        printf("5. Exit\n");
        printf("Choose an option: ");
        scanf(" %c", &choice);
        switch (choice) {
            case '1':
                printf("Enter process name: ");
                scanf("%s", name);
                printf("Enter process priority: ");
                scanf("%d", &priority);
                addProcess(&taskManager, name, priority);
                break;
            case '2':
                printf("Enter process name: ");
                scanf("%s", name);
                killProcess(&taskManager, name);
                break;
            case '3':
                printf("Enter process priority: ");
                scanf("%d", &priority);
                killPriorityProcess(&taskManager, priority);
                break;
            case '4':
                listProcesses(taskManager);
                break;
            case '5':
                printf("Exiting task manager.\n");
                return;
            default:
                printf("Invalid option. Please choose a valid option.\n");
        }
    }
}

int main() {
    taskManagerMain();
    return 0;
}
