public class CalculatorGUI {
    private JFrame frame;
    private JTextField numberField1, numberField2;
    private JTextField resultField;
    private JButton addButton, subtractButton, multiplyButton, divideButton;

    public CalculatorGUI() {
        createGUI();
    }

    private void createGUI() {
        frame = new JFrame("Calculator");
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.setSize(300, 200);
        frame.setLayout(new BorderLayout());

        // Input fields
        JPanel inputPanel = new JPanel();
        inputPanel.setLayout(new FlowLayout());
        inputPanel.add(new JLabel("Number 1:"));
        numberField1 = new JTextField(10);
        inputPanel.add(numberField1);
        inputPanel.add(new JLabel("Number 2:"));
        numberField2 = new JTextField(10);
        inputPanel.add(numberField2);
        frame.add(inputPanel, BorderLayout.NORTH);

        // Operation buttons
        JPanel buttonPanel = new JPanel();
        buttonPanel.setLayout(new GridLayout(4, 2));
        addButton = new JButton("+");
        addButton.addActionListener(new ButtonListener());
        buttonPanel.add(addButton);
        subtractButton = new JButton("-");
        subtractButton.addActionListener(new ButtonListener());
        buttonPanel.add(subtractButton);
        multiplyButton = new JButton("*");
        multiplyButton.addActionListener(new ButtonListener());
        buttonPanel.add(multiplyButton);
        divideButton = new JButton("/");
        divideButton.addActionListener(new ButtonListener());
        buttonPanel.add(divideButton);
        frame.add(buttonPanel, BorderLayout.CENTER);

        // Result field
        resultField = new JTextField(10);
        frame.add(resultField, BorderLayout.SOUTH);

        frame.setVisible(true);
    }

    private class ButtonListener implements ActionListener {
        @Override
        public void actionPerformed(ActionEvent e) {
            String operation = e.getActionCommand();
            double num1 = Double.parseDouble(numberField1.getText());
            double num2 = Double.parseDouble(numberField2.getText());
            double result = 0;

            switch (operation) {
                case "+":
                    result = add(num1, num2);
                    break;
                case "-":
                    result = subtract(num1, num2);
                    break;
                case "*":
                    result = multiply(num1, num2);
                    break;
                case "/":
                    result = divide(num1, num2);
                    break;
            }

            resultField.setText(String.valueOf(result));
        }
    }

    private double add(double num1, double num2) {
        return num1 + num2;
    }

    private double subtract(double num1, double num2) {
        return num1 - num2;
    }

    private double multiply(double num1, double num2) {
        return num1 * num2;
    }

    private double divide(double num1, double num2) {
        if (num2 == 0) {
            throw new ArithmeticException("Cannot divide by zero");
        }
        return num1 / num2;
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(CalculatorGUI::new);
    }
}
