use std::collections::HashMap;
use std::error::Error;
use std::fmt;

// Define a custom error type for event management
#[derive(Debug)]
enum EventManagementError {
    EventNotFound,
    InvalidEventType,
}

impl fmt::Display for EventManagementError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match *self {
            EventManagementError::EventNotFound => write!(f, "Event not found"),
            EventManagementError::InvalidEventType => write!(f, "Invalid event type"),
        }
    }
}

impl Error for EventManagementError {}

// Define a struct to represent events
struct Event {
    name: String,
    date: String,
}

// Implement a trait to manage events
trait EventManagement {
    fn add_event(&mut self, name: String, date: String) -> Result<(), EventManagementError>;
    fn remove_event(&mut self, name: String) -> Result<(), EventManagementError>;
    fn get_event(&self, name: String) -> Option<String>;
    fn list_events(&self) -> Vec<String>;
}

// Implement the EventManagement trait
struct EventManager {
    events: HashMap<String, Event>,
}

impl EventManager {
    fn new() -> Self {
        EventManager {
            events: HashMap::new(),
        }
    }
}

impl EventManagement for EventManager {
    fn add_event(&mut self, name: String, date: String) -> Result<(), EventManagementError> {
        if self.events.contains_key(&name) {
            return Err(EventManagementError::EventNotFound);
        }
        self.events.insert(name, Event { name, date });
        Ok(())
    }

    fn remove_event(&mut self, name: String) -> Result<(), EventManagementError> {
        if !self.events.contains_key(&name) {
            return Err(EventManagementError::EventNotFound);
        }
        self.events.remove(&name);
        Ok(())
    }

    fn get_event(&self, name: String) -> Option<String> {
        self.events.get(&name).map(|event| event.date.clone())
    }

    fn list_events(&self) -> Vec<String> {
        self.events.keys().cloned().collect()
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut manager = EventManager::new();

    // Add events
    manager.add_event("Event 1".to_string(), "2023-01-01".to_string())?;
    manager.add_event("Event 2".to_string(), "2023-01-02".to_string())?;

    // List events
    println!("Events:");
    for event in manager.list_events() {
        println!("{}", event);
    }

    // Get event
    if let Some(date) = manager.get_event("Event 1".to_string()) {
        println!("Event 1 date: {}", date);
    }

    // Remove event
    manager.remove_event("Event 2".to_string())?;

    // List events
    println!("Events after removal:");
    for event in manager.list_events() {
        println!("{}", event);
    }

    Ok(())
}
