class TodoManager {
    private tasks: { task_id: number; description: string; completed: boolean }[];

    constructor() {
        this.tasks = [];
    }

    addTask(taskDescription: string): void {
        const newTask = {
            task_id: this.tasks.length + 1,
            description: taskDescription,
            completed: false,
        };
        this.tasks.push(newTask);
    }

    completeTask(taskId: number): void {
        const taskIndex = this.tasks.findIndex((task) => task.task_id === taskId);
        if (taskIndex !== -1) {
            this.tasks[taskIndex].completed = true;
        } else {
            console.log(`Task with ID ${taskId} does not exist.`);
        }
    }

    deleteTask(taskId: number): void {
        const taskIndex = this.tasks.findIndex((task) => task.task_id === taskId);
        if (taskIndex !== -1) {
            this.tasks.splice(taskIndex, 1);
        } else {
            console.log(`Task with ID ${taskId} does not exist.`);
        }
    }

    listTasks(): void {
        for (const task of this.tasks) {
            const taskStatus = task.completed ? "Completed" : "Not Completed";
            console.log(`Task ID: ${task.task_id}, Description: ${task.description}, Status: ${taskStatus}`);
        }
    }
}

function manageTodos(): void {
    const todoManager = new TodoManager();
    const readline = require('readline').createInterface({
        input: process.stdin,
        output: process.stdout
    });

    readline.question('Enter command (add, complete, delete, list): ', (command) => {
        switch (command) {
            case 'add':
                readline.question('Enter task description: ', (taskDescription) => {
                    todoManager.addTask(taskDescription);
                    manageTodos();
                });
                break;
            case 'complete':
                readline.question('Enter task ID to complete: ', (taskId) => {
                    todoManager.completeTask(parseInt(taskId));
                    manageTodos();
                });
                break;
            case 'delete':
                readline.question('Enter task ID to delete: ', (taskId) => {
                    todoManager.deleteTask(parseInt(taskId));
                    manageTodos();
                });
                break;
            case 'list':
                todoManager.listTasks();
                manageTodos();
                break;
            default:
                console.log('Invalid command. Please try again.');
                manageTodos();
        }
    });
}

manageTodos();
