// Key constants
const int MAX_USER_ID = 1000;

// Struct to hold subscription options
struct SubscriptionOptions {
    int user_id;
    bool subscribed_to_newsletter;
    time_t subscription_date;
};

// Mutex for thread safety
std::mutex subscription_mutex;

// Function to adjust subscription settings
void adjust_subscription(SubscriptionOptions& options) {
    // Lock the mutex to ensure thread safety
    std::lock_guard<std::mutex> lock(subscription_mutex);

    // Toggle the subscription status
    options.subscribed_to_newsletter = !options.subscribed_to_newsletter;

    // Update the subscription date
    time_t current_time = time(0);
    options.subscription_date = current_time;
}

int main() {
    // Example usage
    SubscriptionOptions options;
    options.user_id = 100;
    options.subscribed_to_newsletter = true;

    // Call the function to adjust subscription settings
    adjust_subscription(options);

    // Print the updated subscription settings
    std::cout << "User ID: " << options.user_id << std::endl;
    std::cout << "Subscribed to newsletter: " << (options.subscribed_to_newsletter ? "Yes" : "No") << std::endl;
    std::cout << "Subscription date: " << ctime(&options.subscription_date) << std::endl;

    return 0;
}
