public class TrafficLight {
    private String currentLight;
    private int greenDelay;
    private int yellowDelay;
    private int redDelay;

    public static final int GREEN_DELAY = 5;
    public static final int YELLOW_DELAY = 2;
    public static final int RED_DELAY = 10;
    public static final String INITIAL_LIGHT = "Green";

    public TrafficLight() {
        this.currentLight = INITIAL_LIGHT;
        this.greenDelay = GREEN_DELAY;
        this.yellowDelay = YELLOW_DELAY;
        this.redDelay = RED_DELAY;
    }

    public void changeLight(String color) {
        if (color.equals("Green") && !currentLight.equals("Green")) {
            currentLight = color;
        } else if (color.equals("Red") && !currentLight.equals("Red")) {
            currentLight = color;
        } else if (color.equals("Yellow") && !currentLight.equals("Yellow")) {
            currentLight = color;
        } else {
            System.out.println("Invalid light color");
        }
    }

    public String getCurrentLight() {
        return currentLight;
    }

    public void addDelay(int seconds) {
        if (currentLight.equals("Green")) {
            try {
                Thread.sleep(seconds * 1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        } else if (currentLight.equals("Yellow")) {
            try {
                Thread.sleep(seconds * 1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        } else if (currentLight.equals("Red")) {
            try {
                Thread.sleep(seconds * 1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    public void nextLight() {
        if (currentLight.equals("Green")) {
            changeLight("Yellow");
            addDelay(yellowDelay);
            changeLight("Red");
            addDelay(redDelay);
            changeLight("Green");
        } else if (currentLight.equals("Yellow")) {
            changeLight("Green");
            addDelay(greenDelay);
        } else if (currentLight.equals("Red")) {
            changeLight("Green");
            addDelay(greenDelay);
        }
    }

    public static void main(String[] args) {
        TrafficLight trafficLight = new TrafficLight();
        trafficLight.nextLight();
    }
}
