#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <stdbool.h>

#define MAX_SETTING_NAME_LENGTH 256
#define MAX_SETTING_VALUE_LENGTH 1024

typedef struct {
    char setting_name[MAX_SETTING_NAME_LENGTH];
    char setting_value[MAX_SETTING_VALUE_LENGTH];
} Setting;

bool settingExists(char* settingName);

void setSetting(char* settingName, char* settingValue);
void getSetting(char* settingName, char** settingValue);
void resetSetting(char* settingName);
void listAllSettings(Setting* settings, int numSettings);

int main() {
    Setting settings[MAX_SETTING_NAME_LENGTH];

    while (1) {
        printf("Software Settings Manager\n");
        printf("1. SET setting_name setting_value\n");
        printf("2. GET setting_name\n");
        printf("3. RESET setting_name\n");
        printf("4. LIST_ALL\n");
        printf("5. Exit\n");
        printf("Choose an option: ");

        char input[MAX_SETTING_NAME_LENGTH];
        scanf("%255s", input);

        if (strcmp(input, "1") == 0) {
            char settingName[MAX_SETTING_NAME_LENGTH];
            char settingValue[MAX_SETTING_VALUE_LENGTH];
            printf("Enter setting name: ");
            scanf("%255s", settingName);
            printf("Enter setting value: ");
            scanf("%255s", settingValue);
            setSetting(settingName, settingValue);
        } else if (strcmp(input, "2") == 0) {
            char settingName[MAX_SETTING_NAME_LENGTH];
            printf("Enter setting name: ");
            scanf("%255s", settingName);
            getSetting(settingName, NULL);
        } else if (strcmp(input, "3") == 0) {
            char settingName[MAX_SETTING_NAME_LENGTH];
            printf("Enter setting name: ");
            scanf("%255s", settingName);
            resetSetting(settingName);
        } else if (strcmp(input, "4") == 0) {
            listAllSettings(settings, MAX_SETTING_NAME_LENGTH);
        } else if (strcmp(input, "5") == 0) {
            break;
        } else {
            printf("Invalid option. Please choose a valid option.\n");
        }
    }

    return 0;
}

bool settingExists(char* settingName) {
    for (int i = 0; i < MAX_SETTING_NAME_LENGTH; i++) {
        if (strcmp(settingName, settings[i].setting_name) == 0) {
            return true;
        }
    }
    return false;
}

void setSetting(char* settingName, char* settingValue) {
    for (int i = 0; i < MAX_SETTING_NAME_LENGTH; i++) {
        if (strcmp(settingName, settings[i].setting_name) == 0) {
            strcpy(settings[i].setting_value, settingValue);
            return;
        }
    }

    if (settingExists(settingName)) {
        printf("Error: Setting already exists.\n");
    } else {
        strcpy(settings[i].setting_name, settingName);
        strcpy(settings[i].setting_value, settingValue);
    }
}

void getSetting(char* settingName, char** settingValue) {
    for (int i = 0; i < MAX_SETTING_NAME_LENGTH; i++) {
        if (strcmp(settingName, settings[i].setting_name) == 0) {
            if (settingValue) {
                strcpy(*settingValue, settings[i].setting_value);
            }
            return;
        }
    }

    if (settingExists(settingName)) {
        printf("Error: Setting not found.\n");
    } else {
        printf("Error: Setting does not exist.\n");
    }
}

void resetSetting(char* settingName) {
    for (int i = 0; i < MAX_SETTING_NAME_LENGTH; i++) {
        if (strcmp(settingName, settings[i].setting_name) == 0) {
            strcpy(settings[i].setting_value, "default_value");
            return;
        }
    }

    if (settingExists(settingName)) {
        printf("Error: Setting not found.\n");
    } else {
        printf("Error: Setting does not exist.\n");
    }
}

void listAllSettings(Setting* settings, int numSettings) {
    for (int i = 0; i < numSettings; i++) {
        printf("Setting Name: %s\n", settings[i].setting_name);
        printf("Setting Value: %s\n\n", settings[i].setting_value);
    }
}
