#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <string.h>

// Mutex lock for concurrent access
pthread_mutex_t task_mutex = PTHREAD_MUTEX_INITIALIZER;
int task_count = 0;
struct task {
    char *name;
    int duration;
    int status;
    pthread_mutex_t wait_mutex = PTHREAD_MUTEX_INITIALIZER;
    pthread_cond_t wait_cond = PTHREAD_COND_INITIALIZER;
};

// Task structure
struct task *tasks[100];
int task_id = 0;

// Mutex lock for task list
pthread_mutex_t task_list_mutex = PTHREAD_MUTEX_INITIALIZER;

// Function to add a new task to the system
void ADD_TASK(char *task_name, int duration) {
    pthread_mutex_lock(&task_list_mutex);
    // Check if task list is full
    if (task_id >= 100) {
        printf("Task list is full. Cannot add more tasks.\n");
        pthread_mutex_unlock(&task_list_mutex);
        return;
    }
    // Create new task structure
    struct task *new_task = (struct task *)malloc(sizeof(struct task));
    new_task->name = (char *)malloc(strlen(task_name) + 1);
    strcpy(new_task->name, task_name);
    new_task->duration = duration;
    new_task->status = 0;  // Initial status is 0 for new tasks
    tasks[task_id] = new_task;
    task_id++;
    pthread_mutex_unlock(&task_list_mutex);
}

// Function to initiate the task by its name
void START_TASK(char *task_name) {
    pthread_mutex_lock(&task_list_mutex);
    // Check if task exists
    for (int i = 0; i < task_id; i++) {
        if (strcmp(tasks[i]->name, task_name) == 0) {
            pthread_mutex_unlock(&task_list_mutex);
            // Initialize task status to 1 (running)
            tasks[i]->status = 1;
            pthread_cond_signal(&tasks[i]->wait_cond);
            pthread_mutex_unlock(&task_list_mutex);
            return;
        }
    }
    pthread_mutex_unlock(&task_list_mutex);
    printf("Task not found.\n");
}

// Function to check the status of a specified task
int CHECK_TASK(char *task_name) {
    pthread_mutex_lock(&task_list_mutex);
    // Check if task exists
    for (int i = 0; i < task_id; i++) {
        if (strcmp(tasks[i]->name, task_name) == 0) {
            pthread_mutex_unlock(&task_list_mutex);
            return tasks[i]->status;
        }
    }
    pthread_mutex_unlock(&task_list_mutex);
    printf("Task not found.\n");
    return -1;  // Return -1 if task is not found
}

// Function to cancel a task that is either running or waiting
void CANCEL_TASK(char *task_name) {
    pthread_mutex_lock(&task_list_mutex);
    // Check if task exists
    for (int i = 0; i < task_id; i++) {
        if (strcmp(tasks[i]->name, task_name) == 0) {
            pthread_mutex_unlock(&task_list_mutex);
            // Cancel running task
            if (tasks[i]->status == 1) {
                tasks[i]->status = -1;  // Mark task as cancelled
                pthread_cond_broadcast(&tasks[i]->wait_cond);
            }
            // Cancel waiting task
            else if (tasks[i]->status == 0) {
                pthread_mutex_lock(&tasks[i]->wait_mutex);
                tasks[i]->status = -1;  // Mark task as cancelled
                pthread_cond_broadcast(&tasks[i]->wait_cond);
                pthread_mutex_unlock(&tasks[i]->wait_mutex);
            }
            pthread_mutex_unlock(&task_list_mutex);
            return;
        }
    }
    pthread_mutex_unlock(&task_list_mutex);
    printf("Task not found.\n");
}

int main() {
    pthread_mutex_lock(&task_list_mutex);
    // Create sample tasks
    ADD_TASK("Task1", 10);
    ADD_TASK("Task2", 20);
    pthread_mutex_unlock(&task_list_mutex);

    // Start tasks
    START_TASK("Task1");
    START_TASK("Task2");

    // Check task status
    printf("Task1 status: %d\n", CHECK_TASK("Task1"));
    printf("Task2 status: %d\n", CHECK_TASK("Task2"));

    // Cancel tasks
    CANCEL_TASK("Task1");
    CANCEL_TASK("Task2");

