#include <fstream>
#include <iostream>
#include <string>

class FileManager {
public:
    FileManager();
    ~FileManager();

    void openFile(const std::string& fileName);
    void writeFile(const std::string& data);
    std::string readFile();
    void closeFile();

private:
    std::ifstream fileStream;
    std::string filePath;
};

FileManager::FileManager() : filePath("") {}

FileManager::~FileManager() {
    if (fileStream.is_open()) {
        fileStream.close();
    }
}

void FileManager::openFile(const std::string& fileName) {
    if (fileName.empty()) {
        throw std::invalid_argument("File name cannot be empty.");
    }

    filePath = fileName;
    fileStream.open(filePath);

    if (!fileStream.is_open()) {
        throw std::runtime_error("Failed to open file " + filePath + ". Ensure the file exists.");
    }
}

void FileManager::writeFile(const std::string& data) {
    if (fileStream.is_open()) {
        fileStream << data;
    } else {
        throw std::runtime_error("File is not open.");
    }
}

std::string FileManager::readFile() {
    if (fileStream.is_open()) {
        std::string data;
        std::getline(fileStream, data);
        return data;
    } else {
        throw std::runtime_error("File is not open.");
    }
}

void FileManager::closeFile() {
    if (fileStream.is_open()) {
        fileStream.close();
        filePath = "";
    } else {
        throw std::runtime_error("File is not open.");
    }
}
