from typing import Dict, List

class AppointmentManager:
    def __init__(self):
        self.appointments: Dict[int, dict] = {}

    def book_appointment(self, date: str, time: str, doctor_id: int) -> bool:
        if (date, time) in [(d, t) for d, t in self.appointments.values() if t == time]:
            return False
        appointment_id = len(self.appointments) + 1
        self.appointments[appointment_id] = {"date": date, "time": time, "doctor_id": doctor_id}
        return True

    def cancel_appointment(self, appointment_id: int) -> bool:
        if appointment_id not in self.appointments:
            return False
        del self.appointments[appointment_id]
        return True

    def reschedule_appointment(self, appointment_id: int, new_date: str, new_time: str) -> bool:
        if appointment_id not in self.appointments:
            return False
        for existing_appointment in self.appointments.values():
            if (existing_appointment["date"], existing_appointment["time"]) == (new_date, new_time):
                return False
        self.appointments[appointment_id]["date"] = new_date
        self.appointments[appointment_id]["time"] = new_time
        return True


def schedule_appointment() -> AppointmentManager:
    return AppointmentManager()


# Example usage:
manager = schedule_appointment()
print(manager.book_appointment("2024-03-18", "10:00", 1))  # Returns: True
