use std::io;
use std::str::FromStr;

enum CalculatorResult {
    Sum(i32, i32),
    Difference(i32, i32),
    Product(i32, i32),
    DivisionResult(i32, i32),
    DivisionError,
}

fn parse_input(input: &str) -> Option<CalculatorResult> {
    let mut parts = input.split_whitespace();
    match parts.next() {
        Some("ADD") => {
            let num1 = parts.next().unwrap().parse::<i32>().unwrap();
            let num2 = parts.next().unwrap().parse::<i32>().unwrap();
            Some(CalculatorResult::Sum(num1, num2))
        }
        Some("SUBTRACT") => {
            let num1 = parts.next().unwrap().parse::<i32>().unwrap();
            let num2 = parts.next().unwrap().parse::<i32>().unwrap();
            Some(CalculatorResult::Difference(num1, num2))
        }
        Some("MULTIPLY") => {
            let num1 = parts.next().unwrap().parse::<i32>().unwrap();
            let num2 = parts.next().unwrap().parse::<i32>().unwrap();
            Some(CalculatorResult::Product(num1, num2))
        }
        Some("DIVIDE") => {
            let num1 = parts.next().unwrap().parse::<i32>().unwrap();
            let num2 = parts.next().unwrap().parse::<i32>().unwrap();
            if num2 == 0 {
                Some(CalculatorResult::DivisionError)
            } else {
                Some(CalculatorResult::DivisionResult(num1, num2))
            }
        }
        _ => None,
    }
}

fn main() {
    loop {
        println!("Enter a calculation (or 'q' to quit):");
        let mut input = String::new();
        io::stdin().read_line(&mut input).unwrap();
        match input.trim() {
            "q" => break,
            _ => {
                let result = parse_input(input.trim());
                match result {
                    Some(CalculatorResult::Sum(num1, num2)) => println!("{} + {} = {}", num1, num2, num1 + num2),
                    Some(CalculatorResult::Difference(num1, num2)) => println!("{} - {} = {}", num1, num2, num1 - num2),
                    Some(CalculatorResult::Product(num1, num2)) => println!("{} * {} = {}", num1, num2, num1 * num2),
                    Some(CalculatorResult::DivisionResult(num1, num2)) => println!("{} / {} = {}", num1, num2, num1 / num2),
                    Some(CalculatorResult::DivisionError) => println!("Error: Division by zero"),
                    None => println!("Invalid input"),
                }
            }
        }
    }
}
