class ShoppingCart {
    constructor() {
        this.cart = {};
        this.productIds = [];
    }

    addProduct(productId, quantity) {
        // Adds a product with a specified quantity to the shopping cart.
        // @param {string} productId - Unique identifier for the product.
        // @param {number} quantity - Quantity of the product to add.
        if (quantity <= 0) {
            throw new Error("Quantity must be a positive integer.");
        }
        if (!this.cart[productId]) {
            this.cart[productId] = quantity;
            this.productIds.push(productId);
        } else {
            this.cart[productId] += quantity;
        }
    }

    removeProduct(productId) {
        // Removes a product identified by its productId from the shopping cart.
        // @param {string} productId - Unique identifier for the product.
        // @throws {Error} If the productId is not found in the cart.
        if (!this.cart[productId]) {
            throw new Error(`Product with id ${productId} not found in the cart.`);
        }
        delete this.cart[productId];
        this.productIds = this.productIds.filter(id => id !== productId);
    }

    updateProduct(productId, quantity) {
        // Updates the quantity of a specific product in the shopping cart.
        // @param {string} productId - Unique identifier for the product.
        // @param {number} quantity - New quantity of the product.
        // @throws {Error} If the productId is not found in the cart or if the quantity is not a positive integer.
        if (!this.cart[productId]) {
            throw new Error(`Product with id ${productId} not found in the cart.`);
        }
        if (quantity <= 0) {
            throw new Error("Quantity must be a positive integer.");
        }
        this.cart[productId] = quantity;
    }

    getProduct(productId) {
        // Retrieves the quantity of a product in the shopping cart by productId.
        // @param {string} productId - Unique identifier for the product.
        // @returns {number} The quantity of the product.
        // @throws {Error} If the productId is not found in the cart.
        return this.cart[productId] || null;
    }
}

function manageShoppingCart() {
    const cart = new ShoppingCart();

    // Add commands
    const commands = {
        addProduct: (productId, quantity) => {
            cart.addProduct(productId, quantity);
        },
        removeProduct: (productId) => {
            cart.removeProduct(productId);
        },
        updateProduct: (productId, quantity) => {
            cart.updateProduct(productId, quantity);
        },
        getProduct: (productId) => {
            return cart.getProduct(productId);
        }
    };

    // Example usage:
    commands.addProduct("prod1", 10);
    commands.addProduct("prod2", 20);
    console.log(commands.getProduct("prod1"));  // Output: 10
    commands.updateProduct("prod1", 30);
    console.log(commands.getProduct("prod1"));  // Output: 30
    commands.removeProduct("prod2");
    console.log(commands.getProduct("prod2"));  // Output: null
}

manageShoppingCart();
