import java.util.ArrayList;
import java.util.List;

public class EmailManager {
    private List<String> subscriptions;
    private List<String> unsubscribedAddresses;

    public EmailManager() {
        this.subscriptions = new ArrayList<>();
        this.unsubscribedAddresses = new ArrayList<>();
    }

    public void subscribe(String emailAddress) {
        if (subscriptions.contains(emailAddress)) {
            throw new IllegalArgumentException("Email address is already subscribed.");
        }
        subscriptions.add(emailAddress);
    }

    public void unsubscribe(String emailAddress) {
        if (!subscriptions.contains(emailAddress)) {
            unsubscribedAddresses.add(emailAddress);
        }
        subscriptions.remove(emailAddress);
    }

    public List<String> listSubscriptions() {
        return new ArrayList<>(subscriptions);
    }

    public boolean isSubscribed(String emailAddress) {
        return subscriptions.contains(emailAddress);
    }

    public static void main(String[] args) {
        EmailManager emailManager = new EmailManager();
        System.out.println(emailManager.isSubscribed("test@example.com")); // false
        emailManager.subscribe("test@example.com");
        System.out.println(emailManager.listSubscriptions()); // [test@example.com]
        emailManager.subscribe("test@example.com");
        try {
            emailManager.subscribe("test@example.com");
        } catch (IllegalArgumentException e) {
            System.out.println(e.getMessage()); // Email address is already subscribed.
        }
        emailManager.unsubscribe("test@example.com");
        System.out.println(emailManager.listSubscriptions()); // []
        emailManager.unsubscribe("nonExistent@example.com");
        System.out.println(emailManager.isSubscribed("nonExistent@example.com")); // false
        System.out.println(emailManager.isSubscribed("test@example.com")); // false
        System.out.println(emailManager.listSubscriptions()); // []
    }
}
