public class ElectronicsStoreInventory {
    private static final String PRODUCT_NOT_FOUND_MESSAGE = "Product not found in inventory.";
    private static final int MAX_PRODUCTS = 1000;

    private Product[] inventory;
    private int currentProducts;

    public ElectronicsStoreInventory() {
        this.inventory = new Product[MAX_PRODUCTS];
        this.currentProducts = 0;
    }

    public void addProduct(String name, int quantity) {
        for (int i = 0; i < currentProducts; i++) {
            if (inventory[i].getName().equals(name)) {
                inventory[i].setQuantity(inventory[i].getQuantity() + quantity);
                return;
            }
        }

        if (currentProducts < MAX_PRODUCTS) {
            inventory[currentProducts] = new Product(name, quantity);
            currentProducts++;
        } else {
            System.out.println("Inventory is full. Cannot add more products.");
        }
    }

    public void removeProduct(String name) {
        for (int i = 0; i < currentProducts; i++) {
            if (inventory[i].getName().equals(name)) {
                for (int j = i; j < currentProducts - 1; j++) {
                    inventory[j] = inventory[j + 1];
                }
                currentProducts--;
                return;
            }
        }
        System.out.println(PRODUCT_NOT_FOUND_MESSAGE);
    }

    public int getProductQuantity(String name) {
        for (int i = 0; i < currentProducts; i++) {
            if (inventory[i].getName().equals(name)) {
                return inventory[i].getQuantity();
            }
        }
        return 0;
    }

    public void updateProductQuantity(String name, int newQuantity) {
        for (int i = 0; i < currentProducts; i++) {
            if (inventory[i].getName().equals(name)) {
                inventory[i].setQuantity(newQuantity);
                return;
            }
        }
        System.out.println(PRODUCT_NOT_FOUND_MESSAGE);
    }

    private static class Product {
        private String name;
        private int quantity;

        public Product(String name, int quantity) {
            this.name = name;
            this.quantity = quantity;
        }

        public String getName() {
            return name;
        }

        public int getQuantity() {
            return quantity;
        }

        public void setQuantity(int quantity) {
            this.quantity = quantity;
        }
    }

    public static void main(String[] args) {
        ElectronicsStoreInventory inventory = new ElectronicsStoreInventory();
    }
}
