    struct statvfs statvfs;
    statvfs("/");

    double cpuUsage = (statvfs.f_frsize * statvfs.f_blocks) / (double)statvfs.f_frsize / (double)statvfs.f_bfree * 100;
    printf("CPU Usage: %.2f%%\n", cpuUsage);
}

// Function to calculate memory usage
void calculateMemoryUsage(void) {
    struct statvfs statvfs;
    statvfs("/");

    double memoryUsage = (statvfs.f_frsize * statvfs.f_blocks) / (double)statvfs.f_frsize / (double)statvfs.f_bavail * 100;
    printf("Memory Usage: %.2f%%\n", memoryUsage);
}

// Function to calculate disk usage
void calculateDiskUsage(void) {
    struct statvfs statvfs;
    statvfs("/");

    double diskUsage = (statvfs.f_frsize * statvfs.f_blocks) / (double)statvfs.f_frsize / (double)statvfs.f_bfree * 100;
    printf("Disk Usage: %.2f%%\n", diskUsage);
}

// Server implementation
void Server::startServer(int port) {
    serverSocket = socket(AF_INET, SOCK_STREAM, 0);
    if (serverSocket < 0) {
        perror("socket creation failed");
        exit(1);
    }

    serverAddress.sin_family = AF_INET;
    serverAddress.sin_port = htons(port);
    inet_pton(AF_INET, "127.0.0.1", &serverAddress.sin_addr);

    if (bind(serverSocket, (struct sockaddr*)&serverAddress, sizeof(serverAddress)) < 0) {
        perror("bind failed");
        exit(1);
    }

    if (listen(serverSocket, 3) < 0) {
        perror("listen failed");
        exit(1);
    }

    printf("Server started on port %d...\n", port);

    while (1) {
        clientSocket = accept(serverSocket, (struct sockaddr*)&clientAddress, sizeof(clientAddress));
        if (clientSocket < 0) {
            perror("accept failed");
            continue;
        }

        printf("Connection from client IP address %s and port %d...\n", inet_ntoa(clientAddress.sin_addr), ntohs(clientAddress.sin_port));

        receiveRequest(clientSocket);
        sendStatistics(clientSocket);
    }
}

