use std::time::{SystemTime, Duration};
use std::collections::HashMap;

struct SessionManager {
    user_sessions: HashMap<String, (SystemTime, u32)>,
}

impl SessionManager {
    fn new() -> Self {
        SessionManager {
            user_sessions: HashMap::new(),
        }
    }

    fn start_session(&mut self, user_id: String) {
        let current_time = SystemTime::now();
        self.user_sessions.insert(user_id.clone(), (current_time, 0));
    }

    fn check_session(&self, user_id: String, session_duration: u32) -> bool {
        match self.user_sessions.get(&user_id) {
            Some((start_time, _)) => {
                let elapsed_time = SystemTime::now().duration_since(start_time).unwrap().as_secs();
                elapsed_time <= session_duration * 60
            }
            None => false,
        }
    }

    fn end_session(&mut self, user_id: String) {
        self.user_sessions.remove(&user_id).unwrap();
    }
}

fn main() {
    let mut session_manager = SessionManager::new();

    session_manager.start_session("user1".to_string());
    println!("Is session valid? {}", session_manager.check_session("user1".to_string(), 10));

    session_manager.end_session("user1".to_string());
    println!("Is session valid after ending? {}", session_manager.check_session("user1".to_string(), 10));
}
