class WeatherClient:
    def __init__(self, base_url):
        self.base_url = base_url

    def get_current_weather(self, city):
        url = f"{self.base_url}/weather/current/{city}"
        try:
            response = requests.get(url)
            response.raise_for_status()
            return response.json()
        except requests.exceptions.HTTPError as http_err:
            print(f"HTTP error occurred: {http_err}")
            return None
        except Exception as err:
            print(f"Other error occurred: {err}")
            return None

    def register_weather_alert(self, city, alert_type, threshold_temperature):
        url = f"{self.base_url}/weather/alerts"
        payload = {
            "city": city,
            "alert_type": alert_type,
            "threshold_temperature": threshold_temperature
        }
        try:
            response = requests.post(url, json=payload)
            response.raise_for_status()
            return response.json()
        except requests.exceptions.HTTPError as http_err:
            print(f"HTTP error occurred: {http_err}")
            return None
        except Exception as err:
            print(f"Other error occurred: {err}")
            return None

    def update_weather(self, city, temperature, humidity, wind_speed):
        url = f"{self.base_url}/weather/update/{city}"
        payload = {
            "temperature": temperature,
            "humidity": humidity,
            "wind_speed": wind_speed
        }
        try:
            response = requests.put(url, json=payload)
            response.raise_for_status()
            return response.json()
        except requests.exceptions.HTTPError as http_err:
            print(f"HTTP error occurred: {http_err}")
            return None
        except Exception as err:
            print(f"Other error occurred: {err}")
            return None

    def remove_weather_alert(self, city):
        url = f"{self.base_url}/weather/alerts/{city}"
        try:
            response = requests.delete(url)
            response.raise_for_status()
            return response.json()
        except requests.exceptions.HTTPError as http_err:
            print(f"HTTP error occurred: {http_err}")
            return None
        except Exception as err:
            print(f"Other error occurred: {err}")
            return None


