from typing import Dict, List, Tuple

MAX_EXPENSES: int = 100
EXPENSES: Dict[str, float] = {}
TOTAL_EXPENSES: float = 0.0

def add_expense(name: str, amount: float) -> None:
    """Adds an expense under a specific name with a designated amount, updating the total expenses."""
    global TOTAL_EXPENSES
    if len(EXPENSES) < MAX_EXPENSES:
        EXPENSES[name] = amount
        TOTAL_EXPENSES += amount
    else:
        raise ValueError("Maximum number of expenses reached.")

def remove_expense(name: str) -> bool:
    """Removes an expense by its name."""
    global TOTAL_EXPENSES
    if name in EXPENSES:
        del EXPENSES[name]
        TOTAL_EXPENSES -= EXPENSES[name]
        return True
    else:
        return False

def get_expense(name: str) -> float:
    """Retrieves the expense amount using the given name."""
    return EXPENSES.get(name, 0.0)

def total_expenses() -> float:
    """Returns the sum of all recorded expenses."""
    return TOTAL_EXPENSES

def main() -> None:
