        std::lock_guard<std::mutex> lock(mutex);
        songs_.erase(std::remove(songs_.begin(), songs_.end(), songName), songs_.end());
    }

    void play() {
        std::lock_guard<std::mutex> lock(mutex);
        if (songs_.empty()) {
            std::cout << "Playlist is empty." << std::endl;
            return;
        }
        std::cout << "Playing: " << songs_[0] << std::endl;
        songs_.erase(songs_.begin());
    }

    void listSongs() {
        std::lock_guard<std::mutex> lock(mutex);
        if (songs_.empty()) {
            std::cout << "Playlist is empty." << std::endl;
            return;
        }
        std::cout << "Songs in the playlist:" << std::endl;
        for (const auto& song : songs_) {
            std::cout << song << std::endl;
        }
    }

private:
