#define OPERATION_ADD 1
#define OPERATION_SUBTRACT 2
#define OPERATION_MULTIPLY 3
#define OPERATION_DIVIDE 4
#define ERROR_MESSAGE Division by zero is not allowed.

#define END_OF_INPUT 0
#define EXIT_REQUEST 1

#define MAX_OPERANDS 2

int operationCodes[] = {OPERATION_ADD, OPERATION_SUBTRACT, OPERATION_MULTIPLY, OPERATION_DIVIDE};
char *operationNames[] = {"ADD", "SUBTRACT", "MULTIPLY", "DIVIDE"};
char *errorMessages[] = {"", ERROR_MESSAGE};

int main() {
    int operationCode;
    char input[256];
    int operands[MAX_OPERANDS];

    while (1) {
        printf("Enter operation (ADD, SUBTRACT, MULTIPLY, DIVIDE, EXIT, EOF) or a number to exit: ");
        fgets(input, sizeof(input), stdin);

        if (input[0] == EOF) {
            break;
        }

        if (input[0] == 'E' || input[0] == 'e') {
            if (sscanf(input, "%d", &operationCode) == 1) {
                break;
            } else {
                printf("Invalid operation code.\n");
            }
        } else {
            operationCode = atoi(input);
        }

        if (operationCode < 1 || operationCode > 4) {
            printf("Invalid operation code.\n");
            continue;
        }

        if (operationCode == END_OF_INPUT) {
            continue;
        }

        printf("Enter the first operand: ");
        if (sscanf(input, "%d", &operands[0]) != 1) {
            printf("Invalid operand.\n");
            continue;
        }

        printf("Enter the second operand: ");
        if (sscanf(input, "%d", &operands[1]) != 1) {
            printf("Invalid operand.\n");
            continue;
        }

        switch (operationCode) {
            case OPERATION_ADD:
                printf("Result: %d\n", operands[0] + operands[1]);
                break;
            case OPERATION_SUBTRACT:
                printf("Result: %d\n", operands[0] - operands[1]);
                break;
            case OPERATION_MULTIPLY:
                printf("Result: %d\n", operands[0] * operands[1]);
                break;
            case OPERATION_DIVIDE:
                if (operands[1] == 0) {
                    printf("%s\n", errorMessages[operationCode]);
                } else {
                    printf("Result: %d\n", operands[0] / operands[1]);
                }
                break;
        }
    }

    return 0;
}
