from datetime import datetime, timedelta

class SessionManager:
    def __init__(self):
        self.sessions = {}

    def create_session(self, user_id: int, expires_in: int) -> None:
        if user_id not in self.sessions:
            session_expiration = datetime.now() + timedelta(seconds=expires_in)
            self.sessions[user_id] = {
                'session_start_time': datetime.now(),
                'session_expiration': session_expiration
            }
        else:
            raise ValueError("Session for user already exists.")

    def get_session(self, user_id: int) -> dict:
        if user_id in self.sessions:
            session = self.sessions[user_id]
            if datetime.now() > session['session_expiration']:
                raise ValueError("Session has expired.")
            return {
                'session_start_time': session['session_start_time'],
                'session_expiration': session['session_expiration']
            }
        else:
            raise ValueError("No session found for user.")

    def delete_session(self, user_id: int) -> None:
        if user_id in self.sessions:
            del self.sessions[user_id]
        else:
            raise ValueError("No session found for user.")

    def extend_session(self, user_id: int, additional_time: int) -> None:
        if user_id in self.sessions:
            current_session_expiration = self.sessions[user_id]['session_expiration']
            new_expiration_time = current_session_expiration + timedelta(seconds=additional_time)
            self.sessions[user_id]['session_expiration'] = new_expiration_time
        else:
            raise ValueError("No session found for user.")


# Example usage:
if __name__ == "__main__":
    session_manager = SessionManager()

    try:
        session_manager.create_session(1, 3600)  # Create a session that expires in 1 hour
        session_manager.create_session(2, 3600)  # Create a session that expires in 1 hour
    except ValueError as e:
        print(e)

    try:
        print(session_manager.get_session(1))  # Get the active session details for user 1
        print(session_manager.get_session(2))  # Get the active session details for user 2
    except ValueError as e:
        print(e)

    try:
        session_manager.delete_session(1)  # Delete the active session for user 1
    except ValueError as e:
        print(e)

    try:
        session_manager.extend_session(1, 7200)  # Extend the existing session expiration by 2 hours
    except ValueError as e:
        print(e)
