use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;
use std::net::{TcpListener, TcpStream};
use std::io::{Read, Write};

struct ChatServer {
    users: Arc<Mutex<HashMap<String, TcpStream>>>,
    listener: TcpListener,
}

impl ChatServer {
    fn new() -> Self {
        let users = Arc::new(Mutex::new(HashMap::new()));
        let listener = TcpListener::bind("127.0.0.1:8080").unwrap();
        ChatServer { users, listener }
    }

    fn handle_client(&mut self, stream: TcpStream) {
        let mut buffer = [0; 512];
        let mut message = String::new();
        while stream.read(&mut buffer).unwrap() > 0 {
            message.push_str(std::str::from_utf8(&buffer[..]).unwrap());
        }
        let message = message.trim();

        match message.as_str() {
            "JOIN" => {
                let username = message.split_whitespace().nth(1).unwrap();
                if let Some(user) = self.users.lock().unwrap().get_mut(username) {
                    *user = stream;
                    println!("{} has joined the chat", username);
                    self.broadcast(&format!("{} has joined the chat", username));
                } else {
                    println!("{} has joined the chat", username);
                    self.broadcast(&format!("{} has joined the chat", username));
                    *self.users.lock().unwrap().entry(username).or_insert(stream);
                }
            }
            "LEAVE" => {
                if let Some(user) = self.users.lock().unwrap().remove(&message.split_whitespace().nth(1).unwrap()) {
                    println!("{} has left the chat", message.split_whitespace().nth(1).unwrap());
                    self.broadcast(&format!("{} has left the chat", message.split_whitespace().nth(1).unwrap()));
                    user.shutdown().unwrap();
                } else {
                    println!("{} has left the chat", message.split_whitespace().nth(1).unwrap());
                    self.broadcast(&format!("{} has left the chat", message.split_whitespace().nth(1).unwrap()));
                }
            }
            "MESSAGE" => {
                let username = message.split_whitespace().nth(1).unwrap();
                if let Some(user) = self.users.lock().unwrap().get_mut(username) {
                    if let Err(e) = user.write_all(message.trim().as_bytes()).unwrap() {
                        println!("Error sending message: {}", e);
                    }
                    self.broadcast(&format!("{}: {}", username, message.trim()));
                }
            }
            "LIST" => {
                let mut list = String::new();
                for (username, _) in &self.users.lock().unwrap() {
                    list.push_str(username);
                    list.push_str(" ");
                }
                if list.len() > 0 {
                    list.pop();
                }
                println!("{}", list);
            }
            _ => println!("{}", message),
        }
    }

    fn broadcast(&self, message: &str) {
        for (username, stream) in &*self.users.lock().unwrap() {
            if let Err(e) = stream.write_all(message.as_bytes()).unwrap() {
                println!("Error sending message: {}", e);
            }
        }
    }

    fn run(&mut self) {
        for stream in self.listener.incoming() {
            match stream {
                Ok(stream) => {
                    self.handle_client(stream);
                }
                Err(e) => {
                    println!("Error accepting connection: {}", e);
                }
            }
        }
    }
}

fn main() {
    let mut server = ChatServer::new();
    server.run();
}
