#include <string.h>

#define MAX_CUSTOMERS 100
#define MAX_ACCOUNTS 100
#define MAX_AMOUNT 1000.0

typedef struct {
    int customerId;
    double balance;
    int accountNumber;
} CustomerAccount;

CustomerAccount customerAccounts[MAX_ACCOUNTS];
int customerAccountCount = 0;

int createAccount(int customerId, double initialBalance) {
    if (customerAccountCount == MAX_ACCOUNTS) {
        printf("Error: Maximum number of accounts reached.\n");
        return -1;
    }

    for (int i = 0; i < customerAccountCount; i++) {
        if (customerAccounts[i].customerId == customerId) {
            printf("Error: Customer ID already exists.\n");
            return -1;
        }
    }

    customerAccounts[customerAccountCount].customerId = customerId;
    customerAccounts[customerAccountCount].balance = initialBalance;
    customerAccounts[customerAccountCount].accountNumber = customerAccountCount;
    customerAccountCount++;

    return 0;
}

int deposit(int customerId, double amount) {
    for (int i = 0; i < customerAccountCount; i++) {
        if (customerAccounts[i].customerId == customerId) {
            if (customerAccounts[i].balance + amount > MAX_AMOUNT) {
                printf("Error: Insufficient balance for deposit.\n");
                return -1;
            }

            customerAccounts[i].balance += amount;
            return 0;
        }
    }

    printf("Error: Customer ID not found.\n");
    return -1;
}

int withdraw(int customerId, double amount) {
    for (int i = 0; i < customerAccountCount; i++) {
        if (customerAccounts[i].customerId == customerId) {
            if (customerAccounts[i].balance - amount < 0) {
                printf("Error: Insufficient balance for withdrawal.\n");
                return -1;
            }

            customerAccounts[i].balance -= amount;
            return 0;
        }
    }

    printf("Error: Customer ID not found.\n");
    return -1;
}

double getBalance(int customerId) {
    for (int i = 0; i < customerAccountCount; i++) {
        if (customerAccounts[i].customerId == customerId) {
            return customerAccounts[i].balance;
        }
    }

    printf("Error: Customer ID not found.\n");
    return -1.0;
}

int closeAccount(int customerId) {
    for (int i = 0; i < customerAccountCount; i++) {
        if (customerAccounts[i].customerId == customerId) {
            customerAccounts[i].balance = 0.0;
            customerAccounts[i].accountNumber = -1;
            return 0;
        }
    }

    printf("Error: Customer ID not found.\n");
    return -1;
}

int main() {
