class VotingSystem:
    def __init__(self):
        self.voters = {}
        self.candidates = {}

    def register(self, voter_id: str, **kwargs) -> dict:
        if voter_id in self.voters:
            return {"error": f"Voter {voter_id} is already registered"}
        self.voters[voter_id] = kwargs
        return {"message": f"Voter {voter_id} registered successfully"}

    def unregister(self, voter_id: str) -> dict:
        if voter_id not in self.voters:
            return {"error": f"Voter {voter_id} is not registered"}
        del self.voters[voter_id]
        return {"message": f"Voter {voter_id} unregistered successfully"}

    def vote(self, voter_id: str, candidate_name: str) -> dict:
        if voter_id not in self.voters:
            return {"error": f"Voter {voter_id} is not registered"}
        if candidate_name not in self.candidates:
            self.candidates[candidate_name] = 0
        self.candidates[candidate_name] += 1
        self.voters[voter_id]["votes"] = candidate_name
        return {"message": f"Vote for {candidate_name} registered successfully"}

    def results(self) -> dict:
        return {"candidates": self.candidates, "voters": self.voters}


def main():
    voting_system = VotingSystem()

    while True:
        print("Voting System Menu:")
        print("1. Register Voter")
        print("2. Unregister Voter")
        print("3. Vote")
        print("4. Results")
        print("5. Exit")

