            voter_id = input("Enter voter id: ")
            voting_system.register(voter_id)
        elif choice == "2":
            voter_id = input("Enter voter id: ")
            voting_system.unregister(voter_id)
        elif choice == "3":
            voter_id = input("Enter voter id: ")
            candidate_name = input("Enter candidate name: ")
            voting_system.vote(voter_id, candidate_name)
        elif choice == "4":
            print(voting_system.results())
        elif choice == "5":
            break
