        }
    }

    fn add_student(&mut self, student_name: String) -> Result<(), String> {
        if self.students.len() >= MAX_STUDENTS {
            return Err(format!("Maximum number of students reached. Cannot add more students."));
        }
        self.students.push(Student {
            name: student_name,
            present: false,
        });
        Ok(())
    }

    fn remove_student(&mut self, student_name: String) -> Result<(), String> {
        let student_index = self.students.iter().position(|student| student.name == student_name)?;
        if let Some(student) = self.students.remove(student_index) {
            return Ok(());
        }
        Err(format!("Student {} not found in the attendance list.", student_name))
    }

    fn check_in_student(&mut self, student_name: String) -> Result<(), String> {
        let student_index = self.students.iter().position(|student| student.name == student_name)?;
        if let Some(student) = self.students.get_mut(student_index) {
            student.present = true;
            Ok(())
        } else {
            Err(format!("Student {} not found in the attendance list.", student_name))
