#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the structure for a task
typedef struct Task {
    int task_id;
    int priority;
    struct Task* next;
} Task;

// Define the structure for the scheduler
typedef struct Scheduler {
    Task* head;
} Scheduler;

// Function to create a new task
Task* create_task(int task_id, int priority) {
    Task* task = (Task*) malloc(sizeof(Task));
    task->task_id = task_id;
    task->priority = priority;
    task->next = NULL;
    return task;
}

// Function to add a task to the scheduler
void add_task(Scheduler* scheduler, int task_id, int priority) {
    Task* new_task = create_task(task_id, priority);
    if (scheduler->head == NULL || new_task->priority > scheduler->head->priority) {
        new_task->next = scheduler->head;
        scheduler->head = new_task;
    } else {
        Task* current = scheduler->head;
        while (current->next != NULL && current->next->priority >= new_task->priority) {
            current = current->next;
        }
        new_task->next = current->next;
        current->next = new_task;
    }
}

// Function to remove a task from the scheduler
void remove_task(Scheduler* scheduler, int task_id) {
    if (scheduler->head == NULL) {
        printf("Task not found in scheduler.\n");
        return;
    }
    if (scheduler->head->task_id == task_id) {
        Task* temp = scheduler->head;
        scheduler->head = scheduler->head->next;
        free(temp);
        return;
    }
    Task* current = scheduler->head;
    while (current->next != NULL) {
        if (current->next->task_id == task_id) {
            Task* temp = current->next;
            current->next = current->next->next;
            free(temp);
            return;
        }
        current = current->next;
    }
    printf("Task not found in scheduler.\n");
}

// Function to change the priority of a task in the scheduler
void change_priority(Scheduler* scheduler, int task_id, int new_priority) {
    if (scheduler->head == NULL) {
        printf("Scheduler is empty.\n");
        return;
    }
    if (scheduler->head->task_id == task_id) {
        scheduler->head->priority = new_priority;
        return;
    }
    Task* current = scheduler->head;
    while (current->next != NULL) {
        if (current->next->task_id == task_id) {
            current->next->priority = new_priority;
            return;
        }
        current = current->next;
    }
    printf("Task not found in scheduler.\n");
}

// Function to fetch the next task from the scheduler
Task* fetch_next_task(Scheduler* scheduler) {
    if (scheduler->head == NULL) {
        printf("Scheduler is empty.\n");
        return NULL;
    }
    Task* next_task = scheduler->head;
    scheduler->head = scheduler->head->next;
    return next_task;
}

// Function to print the scheduler
void print_scheduler(Scheduler* scheduler) {
    Task* current = scheduler->head;
    while (current != NULL) {
        printf("Task ID: %d, Priority: %d\n", current->task_id, current->priority);
        current = current->next;
    }
}

int main() {
    Scheduler scheduler;
    scheduler.head = NULL;

    add_task(&scheduler, 1, 1);
    add_task(&scheduler, 2, 2);
    add_task(&scheduler, 3, 3);

    print_scheduler(&scheduler);

    remove_task(&scheduler, 2);

    print_scheduler(&scheduler);

    change_priority(&scheduler, 1, 5);

    print_scheduler(&scheduler);

    Task* next_task = fetch_next_task(&scheduler);
    printf("Next Task ID: %d, Priority: %d\n", next_task->task_id, next_task->priority);

    return 0;
}
