function calculateTimeSpan(startTimeStamp, endTimeStamp) {
    // Constants
    const secondsPerMinute = 60;
    const minutesPerHour = 60;
    const hoursPerDay = 24;
    const daysPerYear = 365;

    // Validate timestamps
    if (typeof startTimeStamp !== 'number' || typeof endTimeStamp !== 'number') {
        throw new Error("Both timestamps must be numbers.");
    }

    if (isNaN(startTimeStamp) || isNaN(endTimeStamp)) {
        throw new Error("Invalid timestamp. Please enter a valid number.");
    }

    if (endTimeStamp < startTimeStamp) {
        throw new Error("End time stamp cannot be earlier than start time stamp.");
    }

    // Calculate time span
    const timeDiffInSeconds = endTimeStamp - startTimeStamp;

    const years = Math.floor(timeDiffInSeconds / (daysPerYear * 24 * 60 * 60));
    const remainingSeconds = timeDiffInSeconds % (daysPerYear * 24 * 60 * 60);
    const days = Math.floor(remainingSeconds / (24 * 60 * 60));
    remainingSeconds = remainingSeconds % (24 * 60 * 60);
    const hours = Math.floor(remainingSeconds / (minutesPerHour * 60));
    remainingSeconds = remainingSeconds % (minutesPerHour * 60);
    const minutes = Math.floor(remainingSeconds / secondsPerMinute);
    const seconds = remainingSeconds % secondsPerMinute;

    // Format time span
    const timeSpan = `${years} years, ${days} days, ${hours} hours, ${minutes} minutes, and ${seconds} seconds.`;

    return timeSpan;
}

