using namespace std;

class Passenger {
public:
    string name;
    int flightID;

    Passenger(string name, int flightID) : name(name), flightID(flightID) {}

    string toString() const {
        return name + " - Flight " + to_string(flightID);
    }
};

class Flight {
public:
    int ID;
    string name;
    int totalPassengers;
    vector<Passenger> passengers;

    Flight(int ID, string name) : ID(ID), name(name), totalPassengers(0) {}

    void bookPassenger(Passenger passenger) {
        if (passengers.size() < 10) { // Maximum capacity of 10 passengers per flight
            passengers.push_back(passenger);
            totalPassengers++;
            cout << "Booking successful for passenger " << passenger.name << " on flight " << ID << "." << endl;
        } else {
            cout << "Flight is fully booked. Cannot book passenger " << passenger.name << " on flight " << ID << "." << endl;
        }
    }

    void cancelPassenger(Passenger passenger) {
        auto it = find_if(passengers.begin(), passengers.end(), [&](const Passenger& p) { return p.flightID == passenger.flightID; });
        if (it != passengers.end()) {
            passengers.erase(it);
            totalPassengers--;
            cout << "Booking cancelled for passenger " << passenger.name << " on flight " << ID << "." << endl;
        } else {
            cout << "No booking found for passenger " << passenger.name << " on flight " << ID << "." << endl;
        }
    }

    void displayFlightInfo() const {
        cout << "Flight " << ID << " - " << name << ":" << endl;
        cout << "Total passengers: " << totalPassengers << endl;
        for (const auto& passenger : passengers) {
            cout << passenger.toString() << endl;
        }
    }
};

class FlightReservationSystem {
public:
    map<int, Flight> flights;
    map<int, map<string, Passenger>> passengerList;

    void bookFlight(int flightID, string passengerName) {
        if (flights.find(flightID) == flights.end()) {
            flights[flightID] = Flight(flightID, "Flight " + to_string(flightID));
        }
        Flight& flight = flights[flightID];
        if (flight.bookPassenger(Passenger(passengerName, flightID))) {
            passengerList[flightID][passengerName] = Passenger(passengerName, flightID);
        }
    }

    void cancelFlight(int flightID, string passengerName) {
        if (flights.find(flightID) != flights.end()) {
            Flight& flight = flights[flightID];
            flight.cancelPassenger(Passenger(passengerName, flightID));
            passengerList[flightID].erase(passengerName);
        }
    }

    void displayFlightList() const {
        cout << "Flight List:" << endl;
        for (const auto& flight : flights) {
            flight.second.displayFlightInfo();
            cout << endl;
        }
    }

    void displayPassengerList(int flightID) const {
        if (flights.find(flightID) != flights.end()) {
            Flight& flight = flights[flightID];
            cout << "Passenger List for Flight " << flightID << ":" << endl;
            for (const auto& passenger : flight.passengers) {
                cout << passenger.toString() << endl;
            }
        } else {
            cout << "No flights found for ID " << flightID << "." << endl;
        }
    }
};

int main() {
    FlightReservationSystem system;

    while (true) {
        cout << "Flight Reservation System" << endl;
        cout << "1. Book flight" << endl;
        cout << "2. Cancel flight" << endl;
        cout << "3. Display flight list" << endl;
        cout << "4. Display passenger list for flight" << endl;
        cout << "5. Exit" << endl;
        cout << "Enter your choice: ";
        int choice;
        cin >> choice;

        switch (choice) {
            case 1:
                int flightID;
                string passengerName;
                cout << "Enter flight ID: ";
                cin >> flightID;
                cout << "Enter passenger name: ";
                cin.ignore();
                getline(cin, passengerName);
                system.bookFlight(flightID, passengerName);
                break;
            case 2:
                int cancelFlightID;
                string cancelPassengerName;
                cout << "Enter flight ID: ";
                cin >> cancelFlightID;
                cout << "Enter passenger name: ";
                cin.ignore();
                getline(cin, cancelPassengerName);
                system.cancelFlight(cancelFlightID, cancelPassengerName);
