import java.util.HashMap;
import java.util.Map;

public class ParkingGarage {
    private int totalSpaces;
    private Map<String, String> parkedVehicles;
    private int currentOccupancy;

    public ParkingGarage(int totalSpaces) {
        this.totalSpaces = totalSpaces;
        this.parkedVehicles = new HashMap<>();
        this.currentOccupancy = 0;
    }

    public String parkVehicle(String licensePlate) {
        if (currentOccupancy >= totalSpaces) {
            return "No spots are available in the garage.";
        }
        parkedVehicles.put(licensePlate, "in");
        currentOccupancy++;
        return "Vehicle with license plate " + licensePlate + " has been parked.";
    }

    public String departVehicle(String licensePlate) {
        if (!parkedVehicles.containsKey(licensePlate)) {
            return "Vehicle with license plate " + licensePlate + " is not parked in the garage.";
        }
        parkedVehicles.remove(licensePlate);
        currentOccupancy--;
        return "Vehicle with license plate " + licensePlate + " has departed.";
    }

    public int countAvailableSpaces() {
        return totalSpaces - currentOccupancy;
    }

    public static void main(String[] args) {
        ParkingGarage garage = new ParkingGarage(100);
        System.out.println(garage.parkVehicle("ABC123"));
        System.out.println(garage.parkVehicle("DEF456"));
        System.out.println(garage.parkVehicle("GHI789"));
        System.out.println(garage.countAvailableSpaces());  // Output: 96
        System.out.println(garage.departVehicle("ABC123"));
        System.out.println(garage.countAvailableSpaces());  // Output: 97
        System.out.println(garage.departVehicle("DEF456"));  // Output: Vehicle with license plate DEF456 has departed.
        System.out.println(garage.departVehicle("GHI789"));  // Output: Vehicle with license plate GHI789 is not parked in the garage.
    }
}
