import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;

@RestController
public class ProfileController {

    private Map<String, Profile> profiles = new HashMap<>();

    @PostMapping("/profiles")
    public ResponseEntity<Profile> createUser(@RequestBody Profile profile) {
        if (profiles.containsKey(profile.getUsername())) {
            return new ResponseEntity<>(HttpStatus.CONFLICT);
        }
        profiles.put(profile.getUsername(), profile);
        return new ResponseEntity<>(profile, HttpStatus.CREATED);
    }

    @GetMapping("/profile/{username}")
    public ResponseEntity<Profile> getUser(@PathVariable String username) {
        if (!profiles.containsKey(username)) {
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
        return new ResponseEntity<>(profiles.get(username), HttpStatus.OK);
    }

    @PutMapping("/profile/{username}")
    public ResponseEntity<Profile> updateUser(@PathVariable String username, @RequestBody Profile profile) {
        if (!profiles.containsKey(username)) {
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
        profiles.put(username, profile);
        return new ResponseEntity<>(profile, HttpStatus.OK);
    }

    @DeleteMapping("/profile/{username}")
    public ResponseEntity<Void> deleteUser(@PathVariable String username) {
        if (!profiles.containsKey(username)) {
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
        profiles.remove(username);
        return new ResponseEntity<>(HttpStatus.NO_CONTENT);
    }

