#include <iostream>

// Node structure for the singly linked list
struct Node {
    int data;
    Node* next;
};

// Constants for stack operations
const std::string PUSH = "push";
const std::string POP = "pop";
const std::string PEEK = "peek";
const std::string SIZE = "size";
const std::string IS_EMPTY = "isEmpty";

// Stack class
class Stack {
private:
    Node* top;
    int size;

public:
    // Constructor to initialize the stack
    Stack() : top(nullptr), size(0) {}

    // Pushes an element onto the stack
    void push(int data) {
        Node* new_node = new Node();
        new_node->data = data;
        new_node->next = top;
        top = new_node;
        size++;
    }

    // Pops the top element from the stack
    void pop() {
        if (top == nullptr) {
            throw std::runtime_error("Stack is empty");
        }
        int data = top->data;
        top = top->next;
        delete top;
        size--;
    }

    // Peeks the top element from the stack
    void peek() {
        if (top == nullptr) {
            throw std::runtime_error("Stack is empty");
        }
        std::cout << top->data << std::endl;
    }

    // Returns the size of the stack
    int size() {
        return size;
    }

    // Checks if the stack is empty
    bool isEmpty() {
        return top == nullptr;
    }
};

// Function to create a fundamental stack using a singly linked list
Stack createFundamentalStack() {
    return Stack();
}

int main() {
    Stack stack = createFundamentalStack();

    // Example usage
    stack.push(10);
    stack.push(20);
    stack.push(30);

    std::cout << "Size: " << stack.size() << std::endl;  // Output: 3
    std::cout << "IsEmpty: " << (stack.isEmpty() ? "Yes" : "No") << std::endl;  // Output: No

    stack.peek();  // Output: 30
    stack.pop();
    std::cout << "Size: " << stack.size() << std::endl;  // Output: 2

    return 0;
}
