#include <map>
#include <mutex>
#include <stdexcept>

// Define a class to represent the in-memory database
class InMemoryDB {
private:
    // Map to store key-value pairs
    std::map<std::string, std::string> db;
    // Mutex for synchronization
    std::mutex mtx;

public:
    // Function to set a key-value pair
    void set(const std::string& key, const std::string& value) {
        std::lock_guard<std::mutex> lock(mtx);
        db[key] = value;
    }

    // Function to get the value associated with a key
    std::string get(const std::string& key) {
        std::lock_guard<std::mutex> lock(mtx);
        if (db.find(key) == db.end()) {
            throw std::invalid_argument("Key not found");
        }
        return db[key];
    }

    // Function to delete a key-value pair
    void deleteKey(const std::string& key) {
        std::lock_guard<std::mutex> lock(mtx);
        if (db.find(key) == db.end()) {
            throw std::invalid_argument("Key not found");
        }
        db.erase(key);
    }

    // Function to update a key-value pair
    void update(const std::string& key, const std::string& value) {
        std::lock_guard<std::mutex> lock(mtx);
        if (db.find(key) == db.end()) {
            throw std::invalid_argument("Key not found");
        }
        db[key] = value;
    }

    // Function to display the database
    void displayDB() {
        std::lock_guard<std::mutex> lock(mtx);
        for (const auto& pair : db) {
            std::cout << pair.first << ": " << pair.second << std::endl;
        }
    }
};

// Function to execute the in-memory database commands
void executeCommands(InMemoryDB& db, const std::vector<std::string>& commands) {
    for (const auto& command : commands) {
        size_t spacePos = command.find(' ');
        if (spacePos == std::string::npos) {
            std::cout << "Error: Invalid command format" << std::endl;
            continue;
        }

        std::string cmd = command.substr(0, spacePos);
        std::string arg1 = command.substr(spacePos + 1);

        if (cmd == "SET") {
            db.set(arg1, arg2);
        } else if (cmd == "GET") {
            try {
                std::string value = db.get(arg1);
                std::cout << value << std::endl;
            } catch (const std::exception& e) {
                std::cout << e.what() << std::endl;
            }
        } else if (cmd == "DELETE") {
            db.deleteKey(arg1);
        } else if (cmd == "UPDATE") {
            db.update(arg1, arg2);
        } else {
            std::cout << "Error: Invalid command" << std::endl;
        }
    }
}

int main() {
    InMemoryDB db;

    // Define the commands
    std::vector<std::string> commands = {
        "SET name John",
        "SET age 30",
        "GET name",
        "DELETE age",
        "UPDATE name Jane",
        "GET name"
    };

    // Execute the commands
    executeCommands(db, commands);

    // Display the database
    db.displayDB();

    return 0;
}
